import { Transaction, FileModel } from '../types';
import { ContractExecutor } from './engine/ContractExecutor';
import { Fingerprinter } from './processors/Fingerprinter';
import { DateResolver } from './processors/DateResolver';
import { AmountResolver } from './processors/AmountResolver';
import { TypeResolver } from './processors/TypeResolver';
import { NameResolver } from './processors/NameResolver';

export interface BankStrategy {
    name: string;
    canHandle(filename: string, content: any, models?: FileModel[]): boolean;
    parse(content: any, yearAnchor: number, models?: FileModel[], globalKeywords?: string[]): Transaction[] | Promise<Transaction[]>;
}

export interface StrategyResult {
    transactions: Transaction[];
    strategyName: string;
    status?: 'MODEL_REQUIRED';
    fingerprint?: any;
    sample?: string;
    source?: string;
}

export const DatabaseModelStrategy: BankStrategy = {
    name: 'Modelo Aprendido',
    canHandle: (filename, content, models) => {
        if (!models || models.length === 0) return false;
        const rawText = content?.__rawText || (typeof content === 'string' ? content : "");
        const fileFp = Fingerprinter.generate(rawText);
        if (!fileFp) return false;
        return models.some(m => m.is_active && (m.fingerprint.headerHash === fileFp.headerHash || m.fingerprint.structuralPattern === fileFp.structuralPattern));
    },
    parse: async (content, yearAnchor, models, globalKeywords = []) => {
        const rawText = content?.__rawText || (typeof content === 'string' ? content : "");
        const fileFp = Fingerprinter.generate(rawText);
        const model = models?.find(m => m.is_active && (m.fingerprint.headerHash === fileFp?.headerHash || m.fingerprint.structuralPattern === fileFp?.structuralPattern));
        if (!model) return [];
        return await ContractExecutor.apply(model, content);
    }
};

export const GenericStrategy: BankStrategy = {
    name: 'Genérico',
    canHandle: () => true,
    parse: (content, yearAnchor, models, globalKeywords = []) => {
        const rawText = content?.__rawText || (typeof content === 'string' ? content : "");
        const lines = rawText.split(/\r?\n/).filter((l: string) => l.trim().length > 0);
        if (lines.length === 0) return [];

        const delimiter = Fingerprinter.detectDelimiter(lines[0]);
        const grid = lines.map((l: string) => l.split(delimiter));

        const dateIdx = DateResolver.identifyDateColumn(grid);
        const amountIdx = AmountResolver.identifyAmountColumn(grid, [dateIdx]);
        const nameIdx = NameResolver.identifyNameColumn(grid, [dateIdx, amountIdx]);

        const transactions: Transaction[] = [];

        grid.forEach((cols, index) => {
            if (cols.length < 2) return;
            const rawDate = dateIdx !== -1 ? (cols[dateIdx] || '') : '';
            const rawAmount = amountIdx !== -1 ? (cols[amountIdx] || '') : '';
            const rawDesc = nameIdx !== -1 ? (cols[nameIdx] || '') : cols.filter((_, i) => i !== dateIdx && i !== amountIdx).join(' ');

            const isoDate = DateResolver.resolveToISO(rawDate, yearAnchor);
            const stdAmount = AmountResolver.clean(rawAmount);
            const numVal = parseFloat(stdAmount);

            if (isoDate && !isNaN(numVal)) {
                const cleanDesc = NameResolver.clean(NameResolver.cleanGenericNoise(rawDesc), globalKeywords);
                transactions.push({
                    id: `gen-${index}-${Date.now()}`,
                    date: isoDate,
                    description: rawDesc.trim(),
                    rawDescription: cols.join('|'),
                    amount: numVal,
                    originalAmount: rawAmount,
                    cleanedDescription: cleanDesc,
                    contributionType: TypeResolver.resolveFromDescription(rawDesc)
                });
            }
        });
        return transactions;
    }
};

export const StrategyEngine = {
    strategies: [DatabaseModelStrategy, GenericStrategy],
    process: async (filename: string, content: any, models: FileModel[] = [], globalKeywords: string[] = [], overrideModel?: FileModel): Promise<StrategyResult> => {
        const rawText = content?.__rawText || (typeof content === 'string' ? content : "");
        const yearAnchor = DateResolver.discoverAnchorYear(rawText);

        if (rawText) {
            const fileFp = Fingerprinter.generate(rawText);
            const targetModel = overrideModel || models.find(m => m.is_active && (m.fingerprint.headerHash === fileFp?.headerHash || m.fingerprint.structuralPattern === fileFp?.structuralPattern));

            if (targetModel) {
                const txs = await DatabaseModelStrategy.parse(content, yearAnchor, [targetModel], []);
                return { transactions: txs, strategyName: targetModel.name };
            }

            // GOVERNANÇA DE MODELO (V25): Bloqueio formal quando não há modelo casado
            console.warn(`[Executor:MODEL_REQUIRED] Documento sem modelo válido: ${fileFp?.headerHash || 'SEM_HASH'}`);
            return { 
                status: 'MODEL_REQUIRED',
                transactions: [], 
                strategyName: 'IA (Modelo Necessário)',
                fingerprint: fileFp,
                sample: rawText.substring(0, 500),
                source: filename
            };
        }

        let targetModel = overrideModel;
        if (!targetModel) {
            const fileFp = Fingerprinter.generate(rawText);
            targetModel = models.find(m => m.is_active && (m.fingerprint.headerHash === fileFp?.headerHash || m.fingerprint.structuralPattern === fileFp?.structuralPattern));
        }

        if (targetModel) {
            const txs = await DatabaseModelStrategy.parse(content, yearAnchor, [targetModel], []);
            return { transactions: txs, strategyName: targetModel.name };
        }

        const genResult = GenericStrategy.parse(content, yearAnchor, models, globalKeywords) as Transaction[];
        return { transactions: genResult, strategyName: 'Genérico' };
    }
};

import { Transaction, FileModel } from '../types';
import { StrategyEngine, StrategyResult } from '../core/strategies';
import { Fingerprinter } from '../core/processors/Fingerprinter';
import { IngestionOrchestrator } from '../core/engine/IngestionOrchestrator';

export * from './utils/parsingUtils';
export * from './logic/matchingLogic';
export * from './logic/filteringLogic';

export const generateFingerprint = Fingerprinter.generate;

/**
 * 🛠️ ADAPTER ESTRUTURAL (V1)
 */
function normalizeIngestionInput(input: any) {
    if (Array.isArray(input)) return input;
    if (typeof input === 'string') {
        return {
            __rawText: input,
            __source: 'ingestion_string'
        };
    }
    return input;
}

export const findMatchingModel = (content: string, models: FileModel[]): { model: FileModel, score: number } | null => {
    if (!models || models.length === 0) return null;
    const fileFp = Fingerprinter.generate(content);
    if (!fileFp) return null;
    let bestMatch: FileModel | null = null;
    let bestScore = 0;

    for (const model of models) {
        if (!model.is_active) continue;
        const modelFp = model.fingerprint;
        let score = 0;

        if (modelFp.headerHash && fileFp.headerHash && modelFp.headerHash === fileFp.headerHash) score += 85;
        else if (modelFp.structuralPattern && fileFp.structuralPattern && modelFp.structuralPattern === fileFp.structuralPattern) score += 70;

        if (modelFp.columnCount === fileFp.columnCount) score += 10;

        if (score > bestScore && score >= 80) { 
            bestScore = score; 
            bestMatch = model; 
        }
    }
    return bestMatch ? { model: bestMatch, score: bestScore } : null;
};

/**
 * PROCESSADOR DE PIPELINE (V13 - GOVERNANÇA DE MODELO)
 */
export const processFileContent = async (
    content: string, 
    fileName: string, 
    models: FileModel[] = [], 
    globalKeywords: string[] = []
): Promise<StrategyResult & { appliedModel?: any }> => {

    const normalizedContent = IngestionOrchestrator.normalizeRawContent(content);
    const matchResult = findMatchingModel(normalizedContent, models);
    const targetModel = matchResult?.model;

    const adaptedInput = normalizeIngestionInput(normalizedContent);

    const result = await StrategyEngine.process(
        fileName, 
        adaptedInput, 
        models, 
        targetModel ? [] : globalKeywords,
        targetModel
    );

    if (result.status === 'MODEL_REQUIRED') {
        return result;
    }

    const transactions = Array.isArray(result?.transactions) ? result.transactions : [];

    return {
        ...result,
        transactions,
        appliedModel: targetModel ? { id: targetModel.id, name: targetModel.name, confidenceScore: 100 } : undefined
    };
};

export const parseContributors = (content: string, ignoreKeywords: string[] = [], typeKeywords: string[] = []): any[] => {
    const lines = content.split(/\r?\n/).filter(l => l.trim().length > 0);
    if (lines.length < 2) return [];
    const delimiter = Fingerprinter.detectDelimiter(lines[0]);
    const rows = lines.map(l => l.split(delimiter));

    const contributors = rows.slice(1).map(row => ({
        name: row[0] || 'Desconhecido',
        amount: parseFloat(String(row[1] || '0').replace(/[R$\s]/g, '').replace(',', '.')) || 0,
        date: row[2] || ''
    })).filter(c => c.name !== 'Desconhecido');

    return contributors;
};

import { useState, useCallback, useRef } from 'react';
import { 
    MatchResult, 
    Transaction, 
    Church, 
    Bank, 
    FileModel, 
    ComparisonType,
    ContributorFile,
    GroupedReportData,
    ReconciliationStatus
} from '../types';
import { 
    processFileContent, 
    parseContributors, 
    matchTransactions, 
    groupResultsByChurch,
    PLACEHOLDER_CHURCH
} from '../services/processingService';
import { IngestionOrchestrator } from '../core/engine/IngestionOrchestrator';
import { useLiveListSync } from './useLiveListSync';
import { usePersistentState } from './usePersistentState';

export const useReconciliation = ({
    user,
    churches,
    banks,
    fileModels,
    similarityLevel,
    dayTolerance,
    customIgnoreKeywords,
    contributionKeywords,
    learnedAssociations,
    showToast,
    setIsLoading,
    setActiveView
}: any) => {

    const userSuffix = user ? `-${user.id}` : '-guest';
    const [activeBankFiles, setBankStatementFile] = useState<any[]>([]);
    const [contributorFiles, setContributorFiles] = useState<ContributorFile[]>([]);
    const [selectedBankIds, setSelectedBankIds] = useState<string[]>([]);
    const [matchResults, setMatchResults] = useState<MatchResult[]>([]);
    const [reportPreviewData, setReportPreviewData] = useState<{ income: GroupedReportData; expenses: GroupedReportData } | null>(null);
    const [activeReportId, setActiveReportId] = useState<string | null>(null);
    const [hasActiveSession, setHasActiveSession] = useState(false);
    const [comparisonType, setComparisonType] = useState<ComparisonType>('income');
    const [manualIdentificationTx, setManualIdentificationTx] = useState<Transaction | null>(null);
    const [bulkIdentificationTxs, setBulkIdentificationTxs] = useState<Transaction[]>([]);
    const [modelRequiredData, setModelRequiredData] = useState<any | null>(null);

    const [launchedResults, setLaunchedResults] = usePersistentState<MatchResult[]>(`identificapix-launched${userSuffix}`, [], true);

    const processingFilesRef = useRef<Set<string>>(new Set());

    const { persistTransactions, clearRemoteList, hydrate } = useLiveListSync({
        user,
        setBankStatementFile,
        setSelectedBankIds,
        showToast
    });

    const regenerateReportPreview = useCallback((results: MatchResult[]) => {
        const uniqueResults = Array.from(new Map(results.map(r => [r.transaction.id, r])).values());
        const incomeResults = uniqueResults.filter(r => r.transaction.amount >= 0 || r.status === ReconciliationStatus.PENDING);
        const expenseResults = uniqueResults.filter(r => r.transaction.amount < 0 && r.status !== ReconciliationStatus.PENDING);

        setReportPreviewData({
            income: groupResultsByChurch(incomeResults),
            expenses: { 'all_expenses_group': expenseResults }
        });
    }, []);

    const handleStatementUpload = useCallback(async (content: string, fileName: string, bankId: string, rawFile?: File) => {
        const processKey = `${bankId}-${fileName}`;
        if (processingFilesRef.current.has(processKey)) {
            return;
        }

        processingFilesRef.current.add(processKey);
        setIsLoading(true);

        try {
            // EXECUÇÃO DO PIPELINE
            const executorResult = await processFileContent(content, fileName, fileModels, customIgnoreKeywords);

            // GOVERNANÇA: Bloqueio de Lançamento se não houver modelo
            if (executorResult.status === 'MODEL_REQUIRED') {
                setModelRequiredData({
                    ...executorResult,
                    bankId
                });
                setIsLoading(false);
                processingFilesRef.current.delete(processKey);
                return;
            }

            const transactions = Array.isArray(executorResult?.transactions) 
                ? executorResult.transactions 
                : [];

            if (transactions.length === 0) {
                showToast("Nenhuma transação extraída do arquivo.", "error");
                setIsLoading(false);
                processingFilesRef.current.delete(processKey);
                return;
            }

            const stats = await persistTransactions(bankId, transactions);
            showToast(stats.added === 0 ? "Lista Sincronizada." : `Sucesso! Total: ${stats.total}`, "success");
            await hydrate();

        } catch (error: any) {
            console.error("[Pipeline:ERROR] Falha crítica no upload:", error);
            showToast("Erro no processamento do arquivo.", "error");
        } finally {
            processingFilesRef.current.delete(processKey);
            setIsLoading(false);
        }
    }, [fileModels, customIgnoreKeywords, persistTransactions, showToast, hydrate, setIsLoading]);

    const importGmailTransactions = useCallback(async (transactions: Transaction[]) => {
        if (!user || transactions.length === 0) return;

        const gmailKey = `gmail-sync-active`;
        if (processingFilesRef.current.has(gmailKey)) return;

        processingFilesRef.current.add(gmailKey);
        setIsLoading(true);

        try {
            const result = await IngestionOrchestrator.processVirtualData('Gmail', transactions, customIgnoreKeywords);
            const stats = await persistTransactions('gmail-sync', result.transactions);
            showToast(`Gmail sincronizado! Total: ${stats.total}`, "success");
            await hydrate();
        } finally {
            processingFilesRef.current.delete(gmailKey);
            setIsLoading(false);
        }
    }, [user, customIgnoreKeywords, persistTransactions, showToast, setIsLoading, hydrate]);

    const removeBankStatementFile = useCallback(async (bankId: string) => {
        setIsLoading(true);
        try {
            await clearRemoteList(bankId);
            showToast("Lista removida do sistema.", "success");
        } catch (e) {
            showToast("Erro ao remover lista.", "error");
        } finally {
            setIsLoading(false);
        }
    }, [clearRemoteList, showToast, setIsLoading]);

    const resetReconciliation = useCallback(async () => {
        setIsLoading(true);
        try {
            await clearRemoteList('all');
            setMatchResults([]);
            setReportPreviewData(null);
            setContributorFiles([]);
            setHasActiveSession(false);
            showToast("Sistema reiniciado.", "success");
            setActiveView('upload');
        } finally {
            setIsLoading(false);
        }
    }, [clearRemoteList, showToast, setActiveView, setIsLoading]);

    const markAsLaunched = useCallback((txId: string) => {
        setMatchResults(prev => {
            const itemIndex = prev.findIndex(r => r.transaction.id === txId);
            if (itemIndex === -1) return prev;

            const item = prev[itemIndex];

            setLaunchedResults(launched => [{ 
                ...item, 
                launchedAt: new Date().toISOString() 
            }, ...launched]);

            const next = prev.filter(r => r.transaction.id !== txId);
            setTimeout(() => regenerateReportPreview(next), 0);
            return next;
        });
    }, [setMatchResults, setLaunchedResults, regenerateReportPreview]);

    const deleteLaunchedItem = useCallback((txId: string) => {
        setLaunchedResults(prev => prev.filter(r => r.transaction.id !== txId));
        showToast("Item removido do histórico de lançados.", "success");
    }, [setLaunchedResults, showToast]);

    return {
        activeBankFiles, contributorFiles, matchResults, reportPreviewData,
        activeReportId, setActiveReportId, hasActiveSession, setHasActiveSession,
        comparisonType, setComparisonType, selectedBankIds,
        manualIdentificationTx, setManualIdentificationTx,
        bulkIdentificationTxs, setBulkIdentificationTxs,
        modelRequiredData, setModelRequiredData,
        launchedResults, setLaunchedResults, markAsLaunched, deleteLaunchedItem,
        importGmailTransactions, handleStatementUpload, 
        handleContributorsUpload: (content: string, fileName: string, churchId: string) => {
             const church = churches.find((c: any) => c.id === churchId);
             const contributors = parseContributors(content, customIgnoreKeywords, contributionKeywords);
             setContributorFiles(prev => [...prev.filter(f => f.churchId !== churchId), { church, churchId, contributors, fileName }]);
             showToast(`Lista carregada (${contributors.length} nomes).`, "success");
        },
        removeBankStatementFile,
        removeContributorFile: (churchId: string) => setContributorFiles(prev => prev.filter(f => f.churchId !== churchId)),
        toggleBankSelection: (id: string) => setSelectedBankIds(prev => prev.includes(id) ? prev.filter(x => x !== id) : [...prev, id]),
        handleCompare: async () => {
            setIsLoading(true);
            const allTransactions = activeBankFiles.filter(f => selectedBankIds.includes(f.bankId)).flatMap(f => f.processedTransactions || []);

            if (allTransactions.length === 0) { 
                showToast("Sem dados para processar.", "error"); 
                setIsLoading(false); 
                return; 
            }

            const results = matchTransactions(
                allTransactions, 
                contributorFiles, 
                { similarityThreshold: similarityLevel, dayTolerance: dayTolerance }, 
                learnedAssociations, 
                churches, 
                customIgnoreKeywords
            );

            setMatchResults(results);
            regenerateReportPreview(results);
            setHasActiveSession(true);
            setActiveView('reports');
            setIsLoading(false);
            showToast("Processamento concluído!", "success");
        },
        resetReconciliation,
        updateReportData: (updatedRow: MatchResult) => {
            setMatchResults(prev => {
                const next = [...prev];
                const idx = next.findIndex(r => r.transaction.id === updatedRow.transaction.id);
                if (idx !== -1) next[idx] = updatedRow;
                else next.push(updatedRow);
                regenerateReportPreview(next);
                return next;
            });
        },
        revertMatch: (txId: string) => {
            setMatchResults(prev => {
                const next = prev.map(r => r.transaction.id === txId ? { ...r, status: ReconciliationStatus.UNIDENTIFIED, contributor: null, church: PLACEHOLDER_CHURCH } : r);
                regenerateReportPreview(next);
                return next;
            });
        },
        closeManualIdentify: () => { setManualIdentificationTx(null); setBulkIdentificationTxs([]); },
        removeTransaction: (id: string) => {
            setMatchResults(prev => {
                const next = prev.filter(r => r.transaction.id !== id);
                regenerateReportPreview(next);
                return next;
            });
        },
        hydrate,
        setMatchResults,
        setReportPreviewData
    };
};

